    int* cols = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        rows[i] = 0;
        cols[i] = 0;
    }
    for (int i = 0; i < Q; i++) {
        char op[10];
        int idx, val;
        scanf(" %s %d", op, &idx);
        idx--;
        if (op[0] == 'R' && op[1] == 'o' && op[2] == 'w') {
            if (op[3] == 'S') {
                scanf(" %d", &val);
                rows[idx] = val;
            } else {
                int count = 0;
                for (int j = 0; j < N; j++) {
                    if (cols[j] == 0) {
                        count++;
                    }
                }
                printf("%d\n", count);
            }
