        if (op == "RowSet") {
            cin >> val;
            rows[idx] = val;
        } else if (op == "RowQuery") {
            int count = 0;
            for (int j = 0; j < N; j++) {
                if (cols[j] == 0) {
                    count++;
                }
            }
            cout << count << endl;
        } else if (op == "ColSet") {
            cin >> val;
            cols[idx] = val;
