import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] rows = new int[N];
        int[] cols = new int[N];
        for (int i = 0; i < Q; i++) {
            String op = sc.next();
            int idx = sc.nextInt() - 1;
            if (op.equals("RowSet")) {
                int val = sc.nextInt();
                rows[idx] = val;
            } else if (op.equals("RowQuery")) {
                int count = 0;
                for (int j = 0; j < N; j++) {
                    if (cols[j] == 0) {
                        count++;
                    }
                }
                System.out.println(count);
            } else if (op.equals("ColSet")) {
                int val = sc.nextInt();
                cols[idx] = val;
            } else if (op.equals("ColQuery")) {
                int count = 0;
                for (int j = 0; j < N; j++) {
                    if (rows[j] == 0) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
        sc.close();
    }
}

